+  | "output.chunk"
+  // State changes
+  | "state.change"
+  // Tool execution
+  | "tool.start"
+  | "tool.end"
+  // File reservations
+  | "reservation.acquired"
+  | "reservation.released"
+  // Conflicts
+  | "conflict.detected"
+  | "conflict.resolved"
+  // Agent mail
+  | "mail.received"
+  // System
+  | "health.ping"
+  | "error";
