+  cursor: string;
+  /** When the message was created */
+  timestamp: string;
+  /** Channel this message was published to (serialized) */
+  channel: string;
+  /** Message type */
+  type: MessageType;
+  /** Type-specific payload */
+  payload: unknown;
+  /** Optional tracing metadata */
+  metadata?: MessageMetadata;
+}
