+export interface SubscribeMessage {
+  type: "subscribe";
+  /** Channel to subscribe to (serialized string) */
+  channel: string;
+  /** Optional cursor to resume from */
+  cursor?: string;
+}
+
+/**
+ * Unsubscribe from a channel.
